mapper.select:
SELECT id, section_id, author_id, title, content, pinned, featured, view_count, created_at, updated_at
FROM posts
WHERE id = #{id}

mapper.update:
UPDATE posts
SET section_id = #{sectionId}, author_id = #{authorId}, title = #{title}, content = #{content}, pinned = #{pinned}, featured = #{featured}, view_count = #{viewCount}, updated_at = NOW()
WHERE id = #{id}
